import strawberry
from strawberry.http import GraphQLRouter
from sqlalchemy import create_engine, MetaData, Table
from sqlalchemy.orm import sessionmaker

# Define the schema
@strawberry.type
class Product:
    id: int
    name: str
    description: str
    price: float
    reviews: List[Review] = None
    sellers: List[Seller] = None
    categories: List[Category] = None
    images: List[Image] = None

@strawberry.type
class Review:
    id: int
    rating: float
    comment: str
    product_id: int

@strawberry.type
class Seller:
    id: int
    name: str
    email: str
